import{_ as o,o as r,c as a,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"36. Travelling Allowance","description":"","frontmatter":{"title":"36. Travelling Allowance","eba":"Biomedical Engineers 2025-2028","topics":["hours","rosters","allowances","travel"]},"headers":[],"relativePath":"ebas/biomedical-engineers/allowances/36-travelling-allowance.md","filePath":"ebas/biomedical-engineers/allowances/36-travelling-allowance.md"}'),n={name:"ebas/biomedical-engineers/allowances/36-travelling-allowance.md"};function l(s,e,i,p,d,c){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="_36-travelling-allowance" tabindex="-1">36. Travelling Allowance <a class="header-anchor" href="#_36-travelling-allowance" aria-label="Permalink to &quot;36. Travelling Allowance&quot;">​</a></h1><p><strong>36.1</strong> Travel - normal working hours</p><p><strong>(a)</strong> Where an Employee is required to use their own vehicle during normal working hours on Employer business, the Employee shall be paid an allowance corresponding with the kilometres rate as determined and updated from time to time by the Australian Taxation Office.</p><p><strong>(b)</strong> An Employee on rostered shifts who is required to use public transport to journey to or from work between 9:00pm and 7:00am, shall be provided with transport (taxi or hire car) if no public transport is available for the inward and/or outward journey. The Employer shall be responsible for the payment of such transport.</p><p><strong>36.2</strong> Travel - recall</p><p><strong>(a)</strong> An Employee who is recalled to work outside the normal working hours and who uses their own vehicle for transport to a place of work and return shall be paid an allowance corresponding with the kilometres rate as determined and updated from time to time by the Australian Taxation Office.</p><p><strong>(b)</strong> An Employee who is recalled who does not use their own vehicle shall be provided, at the expense of the Employer, with a hire car or taxi, for the inward and onward journeys.</p><p><strong>36.3</strong> Reimbursement</p><p><strong>(a)</strong> When an Employee is involved in travelling on duty, all reasonably incurred expenses in respect to fares, meals and accommodation will be met by the Employer on production of receipted account(s) or other evidence acceptable to the Employer.</p><p><strong>(b)</strong> Provided further that the Employee shall not be entitled to reimbursement for those expenses which exceed the mode of transport, meals or the standard of accommodation agreed for the purpose with the Employer.</p>',10)])])}const w=o(n,[["render",l]]);export{m as __pageData,w as default};
